const GRID=40,COLS=Math.ceil(WORLD.w/GRID),ROWS=Math.ceil(WORLD.h/GRID);let navWalkable=[];const navIndex=(x,y)=>y*COLS+x;
function rebuildNavigation(){navWalkable=new Array(COLS*ROWS).fill(false);for(let y=0;y<ROWS;y++)for(let x=0;x<COLS;x++){const px=x*GRID+GRID/2,py=y*GRID+GRID/2;navWalkable[navIndex(x,y)]=canOccupy(px,py,11)}}
