function initAudio(){if(state.audio)return;try{const ac=new(window.AudioContext||window.webkitAudioContext)(),master=ac.createGain();master.gain.value=.105;master.connect(ac.destination);const ambient=ac.createOscillator(),gain=ac.createGain();ambient.type='sawtooth';ambient.frequency.value=38;gain.gain.value=.032;ambient.connect(gain).connect(master);ambient.start();state.audio={ac,master,ambient,gain}}catch(_){state.audio=null}}
function tone(freq=120,duration=.12,type='sine',volume=.18,pan=0){const a=state.audio;if(!a)return;const o=a.ac.createOscillator(),g=a.ac.createGain();o.type=type;o.frequency.setValueAtTime(freq,a.ac.currentTime);g.gain.setValueAtTime(Math.max(.001,volume),a.ac.currentTime);g.gain.exponentialRampToValueAtTime(.001,a.ac.currentTime+duration);let node=g;if(a.ac.createStereoPanner){const p=a.ac.createStereoPanner();p.pan.value=clamp(pan,-1,1);g.connect(p);node=p}o.connect(g);node.connect(a.master);o.start();o.stop(a.ac.currentTime+duration)}
