function emitNoise(x,y,radius,kind='step'){state.noise=Math.max(state.noise,clamp(radius/5,0,100));const sourceRoom=roomAt(x,y),monsterRoom=roomAt(monster.x,monster.y);const effective=sourceRoom&&monsterRoom&&sourceRoom.id!==monsterRoom.id?radius*.72:radius;const heard=distance(monster.x,monster.y,x,y)<=effective;if(heard||kind==='generator'){if(monster.mode!=='chase'){monster.mode='investigate';monster.targetX=x;monster.targetY=y;monster.path=[];monster.repathAt=0;monster.searchCenterX=x;monster.searchCenterY=y}if(!['step','searchTick'].includes(kind))setMessage(kind==='bottle'?'Разбитая колба отвлекла охотника.':'Охотник услышал шум.',1.8)}}
