function nearestContext(){if(state.hidden)return{kind:'exitHide',label:'ВЫЙТИ',duration:.1,target:state.hideTarget};let best=null,bestD=Infinity;const consider=(c,x,y,r=65)=>{const d=distance(player.x,player.y,x,y);if(d<r&&d<bestD){best=c;bestD=d}};for(const c of covers)consider({kind:'hide',label:'СПРЯТАТЬСЯ',duration:.35,target:c},c.x,c.y,58);for(const i of searchables)if(!state.searched.has(i.id)&&performance.now()>state.searchCooldownUntil)consider({kind:'search',label:'ОБЫСКАТЬ '+i.label,target:i},i.x,i.y,70);consider({kind:'generator',label:state.cards>=3?'ЗАПУСТИТЬ':'НУЖНО 3 КАРТЫ',duration:2.25,target:generatorTarget},generatorTarget.x,generatorTarget.y,82);consider({kind:'elevator',label:state.generator?'ВЫЗВАТЬ ЛИФТ':'НЕТ ПИТАНИЯ',duration:1.7,target:elevatorTarget},elevatorTarget.x,elevatorTarget.y,78);return best}
function beginInteraction(){if(!state.running||state.finished||state.interaction||state.searchGame)return;const c=nearestContext();if(!c){setMessage('Рядом нет объекта.',1.4);return}if(c.kind==='generator'&&state.cards<3){setMessage(`Не хватает ключ-карт: ${state.cards}/3.`,2);return}if(c.kind==='elevator'&&!state.generator){setMessage('Сначала восстанови питание.',2);return}if(c.kind==='exitHide'){exitHide();return}if(c.kind==='search'){openSearch(c.target);return}state.interaction={...c,started:performance.now(),progress:0};emitNoise(player.x,player.y,c.kind==='generator'?1400:115,c.kind==='generator'?'generator':'action');tone(c.kind==='generator'?92:205,.12,'square',.13);vibrate('light')}
