function closeSearch(reason=''){state.searchGame=null;searchOverlay.classList.add('hidden');searchPanel.classList.remove('wrong');if(reason)setMessage(reason,2)}
function failSearch(){if(!state.searchGame)return;emitNoise(player.x,player.y,520,'search');state.searchCooldownUntil=performance.now()+1500;closeSearch('Ты не успел. Шум разнёсся по комнате.')}
