function updateSearch(now){const g=state.searchGame;if(!g)return;const left=Math.max(0,(g.endsAt-now)/1000),ratio=clamp(left/g.duration,0,1);searchTime.textContent=left.toFixed(1);searchTimerBar.style.transform=`scaleX(${ratio})`;const md=distance(monster.x,monster.y,player.x,player.y);searchDanger.className=md<180?'high':md<330?'medium':'';searchDanger.textContent=md<180?'ШАГИ: СОВСЕМ РЯДОМ':md<330?'ШАГИ: БЛИЗКО':'ШУМ: РАСТЁТ';if(now-g.lastNoiseAt>720){g.lastNoiseAt=now;emitNoise(player.x,player.y,250,'searchTick');tone(145+Math.floor(rand()*40),.035,'triangle',.035)}if(left<=0)failSearch()}
function enterHide(cover){state.hidden=true;state.hideTarget=cover;state.flashlight=false;state.noise=Math.max(0,state.noise-22);state.hideCheckAt=performance.now()+1200;if(lineOfSight(monster.x,monster.y,player.x,player.y)&&distance(monster.x,monster.y,player.x,player.y)<300)monster.sawHideId=cover.id;player.x=cover.x;player.y=cover.y;tone(74,.12,'sine',.12);setMessage('Ты спрятался. Слушай шаги.',3);vibrate('light')}
