function activateGenerator(){if(state.generator)return;state.generator=true;state.score+=50;state.threat=78;spawnParticles(generatorTarget.x,generatorTarget.y,45,'#70ffc0');tone(88,.8,'sawtooth',.23);warning.textContent='ПИТАНИЕ ВОССТАНОВЛЕНО';warning.classList.add('show');setTimeout(()=>warning.classList.remove('show'),1600);setMessage('Генератор ожил. Охотник идёт сюда!',3.8);emitNoise(generatorTarget.x,generatorTarget.y,1600,'generator');monster.mode='chase';monster.lastSeenX=player.x;monster.lastSeenY=player.y;monster.chaseLostAt=performance.now()+6500;monster.repathAt=0}
